{
  "title": "The end of Roman Britain",
  "keyStage": "ks1",
  "subject": "history",
  "learningOutcome": "I can describe what life was like in Britain after the Romans left.",
  "learningCycles": [
    "Describe changes in Britain after the end of Roman rule.",
    "Identify factors leading to these changes in social and political structures.",
    "Analyse the implications of these changes for daily life in Britain."
  ],
  "priorKnowledge": [
    "The Roman Empire's significant impact on Britain's infrastructure, culture, and daily life.",
    "Key features and functions of Roman roads, buildings, and systems in Britain.",
    "The timeline and primary events of Roman Britain's invasion and departure.",
    "Awareness of societal structures and communities in Britain before Roman rule.",
    "Contact with basic archaeological methods and their use in historical understanding."
  ],
  "keyLearningPoints": [
    "Roman rule ended in Britain around 410 CE when Roman troops withdrew to defend other parts of the empire.",
    "After the Romans' departure, Britain lacked centralised governance, leading to the rise of local rulers.",
    "Anglo-Saxon groups began to migrate to Britain, which influenced the culture and settlement patterns.",
    "The decline of Roman infrastructure, such as roads and aqueducts, affected daily life in Britain.",
    "Christianity persisted and evolved in Britain despite the departure of the Romans."
  ],
  "misconceptions": [
    {
      "misconception": "The Romans completely disappeared from Britain in 410 CE",
      "description": "While Roman troops officially withdrew around this time, their influence on language, culture, and infrastructure persisted in Britain."
    },
    {
      "misconception": "Life in Britain immediately became chaotic after the Romans left",
      "description": "While central governance declined, some regions maintained stability for a period through local rulers and retained Roman practices."
    },
    {
      "misconception": "Christianity was abandoned in Britain after the Romans departed",
      "description": "Christianity continued to be a part of Britain's religious landscape and evolved with the changing societal structures."
    }
  ],
  "keywords": [
    {
      "keyword": "Infrastructure",
      "definition": "The essential physical structures and facilities, such as roads and aqueducts, needed for a society to function effectively"
    },
    {
      "keyword": "Governance",
      "definition": "The action of governing a country or region, including the decision-making processes that define expectations and verify performance"
    },
    {
      "keyword": "Migration",
      "definition": "The movement of people from one region to another, often permanently or for settlement purposes"
    },
    {
      "keyword": "Settlement",
      "definition": "A place where a community establishes itself and builds homes and other necessary structures"
    },
    {
      "keyword": "Christianity",
      "definition": "A religion based on the teachings of Jesus Christ, which played a significant role in historical and cultural developments"
    }
  ],
  "starterQuiz": {
    "version": "v3",
    "questions": [
      {
        "question": "Identify a key feature of Roman roads in Britain.",
        "hint": "Consider how Roman roads were designed to improve travel efficiency.",
        "questionType": "multiple-choice",
        "answers": [
          "They were straight to reduce travel time and connect key locations"
        ],
        "distractors": [
          "They were wide to allow for multiple lanes of traffic",
          "They were paved with cobblestones to prevent plant growth"
        ]
      },
      {
        "question": "What was a significant impact of the Roman Empire on Britain's infrastructure?",
        "hint": "Think about the physical changes brought by Roman rule.",
        "questionType": "multiple-choice",
        "answers": [
          "They constructed advanced roads, baths, and aqueducts"
        ],
        "distractors": [
          "They banned local architectural styles in favour of Roman ones",
          "They prohibited wooden structures entirely"
        ]
      },
      {
        "question": "What was one reason the Romans built aqueducts in Britain?",
        "hint": "Aqueducts were key to providing people with essential resources.",
        "questionType": "multiple-choice",
        "answers": [
          "To supply towns with fresh water"
        ],
        "distractors": [
          "To mark territorial boundaries",
          "To operate as military transportation routes"
        ]
      },
      {
        "question": "Which social feature distinguished Roman Britain from its pre-Roman society?",
        "hint": "This relates to societal changes brought by Roman influence.",
        "questionType": "multiple-choice",
        "answers": [
          "The introduction of Roman hierarchical governance"
        ],
        "distractors": [
          "The development of nomadic lifestyle",
          "The decline of agricultural practices"
        ]
      },
      {
        "question": "What is a primary purpose of archaeology in understanding Roman Britain?",
        "hint": "Consider how objects from the past can inform us.",
        "questionType": "multiple-choice",
        "answers": [
          "To study artefacts that reveal details of life during Roman rule"
        ],
        "distractors": [
          "To validate myths and legends",
          "To analyse global settlement patterns"
        ]
      },
      {
        "question": "Why is the departure of Roman troops in 410 CE significant in British history?",
        "hint": "Reflect on the changes that stemmed from this event.",
        "questionType": "multiple-choice",
        "answers": [
          "It led to the end of centralised Roman governance in Britain"
        ],
        "distractors": [
          "It initiated the decline of Roman technological advancements",
          "It marked the beginning of the Stone Age"
        ]
      }
    ],
